const item = $input.first();
const json = item.json;

// Get the CV URL from the form response
const cvUrl = json['CV / Resume Upload  '] || '';

// Extract Google Drive File ID from any URL format
let fileId = '';

if (cvUrl) {
  // Format 1: https://drive.google.com/open?id=FILE_ID
  const openMatch = cvUrl.match(/[?&]id=([a-zA-Z0-9_-]+)/);

  // Format 2: https://drive.google.com/file/d/FILE_ID/view
  const fileMatch = cvUrl.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);

  // Format 3: https://docs.google.com/document/d/FILE_ID/edit
  const docsMatch = cvUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);

  if (openMatch) {
    fileId = openMatch[1];
  } else if (fileMatch) {
    fileId = fileMatch[1];
  } else if (docsMatch) {
    fileId = docsMatch[1];
  }
}

// Return all original fields + extracted file ID
return [
  {
    json: {
      ...json,
      cv_file_id: fileId
    }
  }
];

